code.value:
/* sélecteur */
h1 {
  /* propriété : valeur */
  color: navy;
  font-size: 2rem;
  margin-bottom: 16px;
}

.btn { background: emerald; }
#logo { width: 120px; }
input[required] { border-color: red; }
* { box-sizing: border-box; }

.btn:hover { background: emerald-light; }
.btn:focus-visible {
  outline: 2px solid skyblue;
}
li:nth-child(odd) { background: #f3f4f6; }

/* Reset universel : à mettre dans toute base CSS */
*, *::before, *::after {
  box-sizing: border-box;
}

.card {
  width: 300px;
  padding: 20px;
  border: 2px solid;
  /* avec border-box : largeur réelle = 300px */
}

.container {
  display: flex;
  /* axe principal horizontal par défaut
     (flex-direction: row) */
}

.navbar {
  display: flex;
  justify-content: space-between;
  /* logo à gauche, menu à droite */
}

/* Centrage parfait, le snippet le plus utile : */
.center {
  display: flex;
  justify-content: center;
  align-items: center;
  min-height: 100vh;
}

.toolbar {
  display: flex;
  gap: 12px;
  /* row-gap et column-gap si tu veux
     des valeurs différentes */
}

.gallery {
  display: flex;
  flex-wrap: wrap;
  gap: 16px;
}
.gallery > * {
  flex: 1 1 200px; /* min 200px, grandit */
}

.container {
  display: grid;
  grid-template-columns: 1fr 1fr 1fr;
  /* 3 colonnes égales */
  gap: 16px;
}

.dashboard {
  display: grid;
  grid-template-columns: 240px 1fr;
  /* sidebar fixe + contenu fluide */
}

.cards {
  display: grid;
  grid-template-columns:
    repeat(auto-fill, minmax(220px, 1fr));
  gap: 16px;
}

/*
  - chaque colonne fait au minimum 220px
  - autant de colonnes que la place le permet
  - chaque colonne s'étire pour combler l'espace
  → magie sans media query
*/

.grid {
  display: grid;
  grid-template-columns: 1fr 1fr 1fr;
  grid-auto-rows: 200px;
  gap: 16px;
}

.hero {
  /* prend les colonnes 1 a 4 (donc 3 colonnes) */
  grid-column: 1 / 4;
  /* ou : grid-column: span 3; */
  grid-row: 1;
}

.sidebar {
  /* derniere colonne, lignes 2 a la fin */
  grid-column: -2 / -1;
  grid-row: 2 / -1;
}

.layout {
  display: grid;
  grid-template-columns: 240px 1fr;
  grid-template-rows: 60px 1fr 40px;
  grid-template-areas:
    "header header"
    "sidebar main"
    "footer footer";
}

.app-header  { grid-area: header; }
.app-sidebar { grid-area: sidebar; }
.app-main    { grid-area: main; }
.app-footer  { grid-area: footer; }

.card {
  display: grid;
  place-items: center;
  /* centre le contenu, parfait pour
     un texte centré sur 2 axes */
}

/* Mobile first : base mobile */
.layout {
  display: flex;
  flex-direction: column;
}

/* Tablette et + */
@media (min-width: 768px) {
  .layout {
    flex-direction: row;
  }
}

/* Desktop large */
@media (min-width: 1280px) {
  .layout { gap: 32px; }
}

img, video, picture {
  max-width: 100%;
  height: auto;
  /* l'image ne dépasse jamais son parent */
}

.btn {
  background: emerald;
  transition: background 200ms ease,
              transform 150ms ease;
}

.btn:hover {
  background: emerald-light;
  transform: scale(1.05);
}

@keyframes pulse {
  0%   { transform: scale(1); opacity: 1; }
  50%  { transform: scale(1.1); opacity: 0.8; }
  100% { transform: scale(1); opacity: 1; }
}

.notification {
  animation: pulse 1.2s ease-in-out infinite;
}

@media (prefers-reduced-motion: reduce) {
  *,
  *::before,
  *::after {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
  }
}
